{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server'

import { revalidatePath } from 'next/cache'
import { cookies } from 'next/headers'

export async function toggleNotifications() {
  const cookieStore = await cookies()
  const current = cookieStore.get('notifications')?.value === 'on'

  // Toggle the preference
  cookieStore.set('notifications', current ? 'off' : 'on', {
    maxAge: 60 * 60 * 24 * 365, // 1 year
    path: '/',
    httpOnly: true,
    sameSite: 'lax',
  })

  // Refresh the current page — this invalidates the server cache and
  // purges the client-side Router Cache, so the page re-fetches with
  // the updated preference on the next render.
  revalidatePath('/')
}
"}

