{"file_path":"/home/user/workspace/app/page.tsx","content":"import { cookies } from 'next/headers'
import { toggleNotifications } from './actions'

export default async function Home() {
  const cookieStore = await cookies()
  const notificationsEnabled = cookieStore.get('notifications')?.value === 'on'

  return (
    <main style={{ fontFamily: 'system-ui, sans-serif', padding: '2rem' }}>
      <h1>Settings</h1>

      <p>
        Notifications:{' '}
        <strong>{notificationsEnabled ? 'On' : 'Off'}</strong>
      </p>

      <form action={toggleNotifications}>
        <button
          type="submit"
          style={{
            padding: '0.5rem 1.25rem',
            fontSize: '1rem',
            cursor: 'pointer',
          }}
        >
          Turn {notificationsEnabled ? 'Off' : 'On'}
        </button>
      </form>
    </main>
  )
}
"}

